function Welcome() {
  return <h1>Salam, React!</h1>;
}

console.log('Komponent yaradıldı');

import React, { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);
  return (
    <div>
      <p>Say: {count}</p>
      <button onClick={() => setCount(count + 1)}>Artır</button>
    </div>
  );
}

console.log('Sayaç komponenti yaradıldı');

